import json
import pymysql
from google.cloud import functions_v1

def query_database(request):
    # Parse the request parameters
    request_json = request.get_json(silent=True)
    request_args = request.args
    
    # Extract parameters (example parameters: table_name, fields, conditions)
    table_name = request_json.get('table_name', None)
    fields = request_json.get('fields', '*')
    conditions = request_json.get('conditions', '')
    
    # Build the SQL query
    query = f"SELECT {fields} FROM {table_name} WHERE 1=1"
    if conditions:
        query += " AND " + conditions
    
    # Connect to Cloud SQL database
    try:
        # Replace with your connection details
        connection = pymysql.connect(
            host='your_host',
            user='your_user',
            password='your_password',
            db='your_database',
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor
        )
        
        with connection.cursor() as cursor:
            # Execute the query
            cursor.execute(query)
            result = cursor.fetchall()
        
        return json.dumps(result), 200
    
    except Exception as e:
        return str(e), 500
    
    finally:
        connection.close()

# This is a serverless function handler
def cloud_function_handler(request):
    return query_database(request)